// Extract text content from RSS/HTML feed, clean it up, pull keywords
const raw = $input.first().json.data || $input.first().json.body || '';

// Strip HTML tags
const stripped = raw.replace(/<[^>]*>/g, ' ').replace(/&[a-z]+;/g, ' ');

// Split into individual items (RSS items separated by title patterns)
const items = stripped.split(/(?=\b[A-Z][a-z]+\s)/)
  .filter(s => s.trim().length > 20)
  .slice(0, 10);

// Combine the most recent posts into one text block
const combinedText = items.join(' ').substring(0, 2000);

// Extract keywords for Polymarket search
const stopWords = new Set(['the', 'a', 'an', 'is', 'are', 'was', 'were', 'will', 'be', 'to', 'of', 'in', 'for', 'on', 'at', 'by', 'and', 'or', 'but', 'not', 'it', 'its', 'has', 'have', 'had', 'that', 'this', 'with', 'from', 'as', 'says', 'said', 'just', 'like', 'than', 'about', 'would', 'could', 'should']);
const words = combinedText
  .replace(/[^a-zA-Z0-9\s]/g, '')
  .split(/\s+/)
  .filter(w => w.length > 3 && !stopWords.has(w.toLowerCase()));

// Count word frequency and pick top keywords
const freq = {};
for (const w of words) {
  const lower = w.toLowerCase();
  freq[lower] = (freq[lower] || 0) + 1;
}
const topKeywords = Object.entries(freq)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(e => e[0])
  .join(' ');

return [{
  json: {
    feedText: combinedText,
    searchQuery: topKeywords,
    postCount: items.length
  }
}];

// Pick the top matching market and extract token ID for pricing
const markets = $input.all();
if (markets.length === 0) {
  return [{ json: { _noMatch: true } }];
}

const top = markets[0].json;

let tokens = top.tokens || [];
if (typeof tokens === 'string') {
  try { tokens = JSON.parse(tokens); } catch(e) { tokens = []; }
}

let clobTokenIds = top.clobTokenIds || [];
if (typeof clobTokenIds === 'string') {
  try { clobTokenIds = JSON.parse(clobTokenIds); } catch(e) { clobTokenIds = []; }
}

let outcomes = top.outcomes || [];
if (typeof outcomes === 'string') {
  try { outcomes = JSON.parse(outcomes); } catch(e) { outcomes = []; }
}

let outcomePrices = top.outcomePrices || [];
if (typeof outcomePrices === 'string') {
  try { outcomePrices = JSON.parse(outcomePrices); } catch(e) { outcomePrices = []; }
}

const firstTokenId = (tokens[0] && tokens[0].tokenId) || clobTokenIds[0] || '';

return [{
  json: {
    question: top.question || top.title || 'Unknown',
    conditionId: top.conditionId || '',
    slug: top.slug || '',
    volume: top.volume || 0,
    tokenId: firstTokenId,
    outcomes,
    outcomePrices,
    _noMatch: false
  }
}];

// Combine news text + market data into an AI analysis prompt
const price = $input.first().json;
const feedData = $('Extract & Clean Text').first().json;
const marketData = $('Pick Top Market').first().json;

const prompt = `Given this recent social media sentiment:
---
${feedData.feedText.substring(0, 1500)}
---

Current Polymarket prediction market:
Question: ${marketData.question}
Current price (YES): $${Number(price.price || price.midpoint || 0).toFixed(3)}
Midpoint: $${Number(price.midpoint || 0).toFixed(3)}
Volume: $${Number(marketData.volume || 0).toLocaleString()}

Based on this sentiment data, should we BUY or SELL the YES token? Respond with JSON only:
{"direction": "BUY" or "SELL", "confidence": 0.0 to 1.0, "reasoning": "1-2 sentence explanation"}`;

return [{
  json: {
    prompt,
    feedText: feedData.feedText.substring(0, 200),
    marketQuestion: marketData.question,
    currentPrice: price.price || price.midpoint || 0,
    tokenId: marketData.tokenId,
    slug: marketData.slug
  }
}];

// Parse AI response and filter by confidence threshold
const aiRaw = $input.first().json;
const promptData = $('Build AI Prompt').first().json;

let text = '';
try {
  text = aiRaw.choices[0].message.content || '';
} catch(e) {
  text = JSON.stringify(aiRaw);
}

let analysis = { direction: 'HOLD', confidence: 0, reasoning: 'Could not parse AI response' };
try {
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    analysis = JSON.parse(jsonMatch[0]);
  }
} catch(e) {
  // Keep defaults
}

return [{
  json: {
    direction: analysis.direction || 'HOLD',
    confidence: Number(analysis.confidence) || 0,
    reasoning: analysis.reasoning || '',
    marketQuestion: promptData.marketQuestion,
    currentPrice: promptData.currentPrice,
    tokenId: promptData.tokenId,
    slug: promptData.slug,
    feedPreview: promptData.feedText
  }
}];

